var e=[{id:`L3_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`언니, 대표님! 빨리요! 이러다 늦어버리겠어요!`,JPN:`お姉ちゃん、代表！　早く！　これじゃ遅くなりますよ！`,ENG:`Rita, Boss! Hurry! We're gonna be late!`,TWN:`姊姊、BOSS！快點快點！要拍了！`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L4_1`,type:`dialog`,speaker:`RITA_CONTEST_NULL_NULL`,text:{KOREA:`이딴 건 왜 찍는다는 거야? 어차피 얼굴이야 매일 질릴 정도로 보는데.`,JPN:`なんでこんなのを撮るんだ？　顔なんてどうせ毎日飽きるほど見てるだろう。`,ENG:`Why are we even doing this? I mean, we see each other every day.`,TWN:`拍這個幹嘛？我們不是天天都在見面，還看不膩嗎？`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`이번에 돌아오면 다같이 사진 찍기로 했잖아요!`,JPN:`今度帰ってくると、みんなで写真撮るって約束したじゃないですか！`,ENG:`But you promised to take a picture once we all came back!`,TWN:`不是說好這次回來後要一起拍張合照嗎！`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`원래 남는 건 사진밖에 없대요. 자자, 카메라 보고 웃어요!`,JPN:`残るのは写真だけですって。はいはい、カメラ見て笑って！`,ENG:`Pictures last longer than memories. Now, smile for the camera!`,TWN:`而且能夠留下來的東西就只有照片。快點，看鏡頭，笑！`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`비키십시오, 리타. 가운데는 대표의 자리입니다. 직원이면 순순히 사이드나 채우시죠.`,JPN:`どいてください、リタ。真ん中は代表の席です。職員なら素直にサイドに下がってください。`,ENG:`Move, Rita. The center position is for the CEO. Employees should fill in the sides.`,TWN:`麗塔，請你讓開，中間C位是BOSS的位置，員工請識相點往旁邊站。`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`시, 시간 없어요! 빨리! 카메라 보고 웃어요!`,JPN:`じ、時間ないですよ！　早く！　カメラ見て笑って！`,ENG:`Th-there's no time! Quick! Smile at the camera!`,TWN:`真的要拍了啦！快點看鏡頭笑！`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RITA_CONTEST_NULL_NULL`,text:{KOREA:`하아…….`,JPN:`はぁ……`,ENG:`*Sigh...*`,TWN:`哀……`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`자, 그럼 치~즈!`,JPN:`はい、じゃあチーズ！`,ENG:`Okay, say cheese!`,TWN:`來囉，西瓜甜不甜～！`},stage:{bg:`BLACK`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`으앙-! 왜 아무도 안 웃는 거예요. 제가 분명 치즈라고 했는데!`,JPN:`わあーん！　どうして誰も笑ってないんですか。私、ちゃんとチーズって言ったのに！`,ENG:`Waah! Why's no one smiling? I said, "say cheese!"`,TWN:`討厭！你們都沒笑，我不是有問西瓜甜不甜嗎！`},stage:{bg:`HORIZON_01_B`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`제 눈꼬리를 잘 보십시오, 대시. 미세하지만 평소보다 올라가 있습니다.`,JPN:`私の目じりをよく見てください、ダッシュ。わずかですが、いつもより上がっています。`,ENG:`Take a look at the tail end of my eye, Dash. It is slightly more elevated than usual.`,TWN:`黛西，你仔細看我的眼尾，雖然很難察覺，但確實有比平常稍微上揚一點。`},stage:{bg:`HORIZON_01_B`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`언니는 아예 다른 데 보고 있어요!`,JPN:`お姉ちゃんは思いっきり目線が外れています！`,ENG:`Rita, you were looking in a completely different direction!`,TWN:`姊姊還給我看別的地方！`},stage:{bg:`HORIZON_01_B`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`RITA_CONTEST_NULL_NULL`,text:{KOREA:`시끄러. 찍었으면 난 일하러 간다.`,JPN:`うるさい。撮ったから、私は仕事に戻る。`,ENG:`Shut it. If we're done here, I'm gonna go back to work.`,TWN:`吵什麼吵，拍完我要去做事了。`},stage:{bg:`HORIZON_01_B`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`언니? 대표님?`,JPN:`お姉ちゃん？　代表？`,ENG:`Rita? Boss?`,TWN:`姊姊？BOSS？`},stage:{bg:`HORIZON_01_B`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`자, 잠시만요. 저도 같이 가요!`,JPN:`ま、待ってください。私も一緒に行きますよ！`,ENG:`Wait up! Take me with you!`,TWN:`等…等我啦！`},stage:{bg:`HORIZON_01_B`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};